/**
 * client-side pagination using posts.json
 * loads latest posts generated by jekyll
 */

const POSTS_PER_PAGE = 5; // posts per page

// fetch latest posts.json (v prevents cache)
fetch('/posts.json?v=1')
  .then(res => res.json())
  .then(posts => {
    renderPagination(posts);   // create page buttons
    renderPosts(posts, 1);     // show first page
  })
  .catch(err => console.error("posts.json error:", err));

/**
 * render posts for selected page
 */
function renderPosts(posts, page) {
  const container = document.querySelector('.post-list');
  container.innerHTML = ''; // clear old posts

  const start = (page - 1) * POSTS_PER_PAGE;
  const list = posts.slice(start, start + POSTS_PER_PAGE);

  list.forEach(p => {
    const item = document.createElement('article');
    item.classList.add('post');

    item.innerHTML = `
      <h2><a href="${p.url}">${p.title}</a></h2>
      <time>${p.date}</time>
    `;

    container.appendChild(item);
  });
}

/**
 * create pagination buttons based on post count
 */
function renderPagination(posts) {
  const totalPages = Math.ceil(posts.length / POSTS_PER_PAGE);
  const box = document.querySelector('.pagination');

  box.innerHTML = ''; // clear old buttons

  for (let i = 1; i <= totalPages; i++) {
    const btn = document.createElement('button');
    btn.textContent = i;

    btn.addEventListener('click', () => {
      renderPosts(posts, i);             // load selected page
      window.scrollTo({ top: 0, behavior: 'smooth' }); // go top
    });

    box.appendChild(btn);
  }
}